-- Create "bom_headers" table
CREATE TABLE "bom_headers" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "version" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "effective_from" timestamptz NULL,
  "effective_to" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "product_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "bom_headers_products_bom_headers" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "bomheader_product_id_status" to table: "bom_headers"
CREATE INDEX "bomheader_product_id_status" ON "bom_headers" ("product_id", "status");
-- Create index "bomheader_product_id_version" to table: "bom_headers"
CREATE UNIQUE INDEX "bomheader_product_id_version" ON "bom_headers" ("product_id", "version");
-- Create "bom_items" table
CREATE TABLE "bom_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "quantity" numeric(20,6) NOT NULL,
  "loss_rate" numeric(20,6) NOT NULL,
  "position" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "bom_header_id" bigint NOT NULL,
  "material_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "bom_items_bom_headers_items" FOREIGN KEY ("bom_header_id") REFERENCES "bom_headers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "bom_items_materials_bom_items" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "bom_items_units_bom_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "bomitem_bom_header_id_material_id" to table: "bom_items"
CREATE INDEX "bomitem_bom_header_id_material_id" ON "bom_items" ("bom_header_id", "material_id");
-- Create "inventory_lots" table
CREATE TABLE "inventory_lots" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject_type" character varying NOT NULL,
  "subject_id" bigint NOT NULL,
  "lot_no" character varying NOT NULL,
  "supplier_lot_no" character varying NULL,
  "color_no" character varying NULL,
  "dye_lot_no" character varying NULL,
  "production_lot_no" character varying NULL,
  "status" character varying NOT NULL DEFAULT 'ACTIVE',
  "received_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "inventorylot_color_no" to table: "inventory_lots"
CREATE INDEX "inventorylot_color_no" ON "inventory_lots" ("color_no");
-- Create index "inventorylot_dye_lot_no" to table: "inventory_lots"
CREATE INDEX "inventorylot_dye_lot_no" ON "inventory_lots" ("dye_lot_no");
-- Create index "inventorylot_subject_type_subject_id_lot_no" to table: "inventory_lots"
CREATE UNIQUE INDEX "inventorylot_subject_type_subject_id_lot_no" ON "inventory_lots" ("subject_type", "subject_id", "lot_no");
-- Create index "inventorylot_supplier_lot_no" to table: "inventory_lots"
CREATE INDEX "inventorylot_supplier_lot_no" ON "inventory_lots" ("supplier_lot_no");
-- Drop index "inventorybalance_subject_type_subject_id_warehouse_id_unit_id" from table: "inventory_balances"
DROP INDEX "inventorybalance_subject_type_subject_id_warehouse_id_unit_id";
-- Modify "inventory_balances" table
ALTER TABLE "inventory_balances" ADD COLUMN "lot_id" bigint NULL, ADD CONSTRAINT "inventory_balances_inventory_lots_inventory_balances" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
-- Create index "inventorybalance_subject_type_subject_id_warehouse_id_unit_id" to table: "inventory_balances"
CREATE UNIQUE INDEX "inventorybalance_subject_type_subject_id_warehouse_id_unit_id" ON "inventory_balances" ("subject_type", "subject_id", "warehouse_id", "unit_id") WHERE (lot_id IS NULL);
-- Create index "inventorybalance_subject_type_subject_id_warehouse_id_unit_id_l" to table: "inventory_balances"
CREATE UNIQUE INDEX "inventorybalance_subject_type_subject_id_warehouse_id_unit_id_l" ON "inventory_balances" ("subject_type", "subject_id", "warehouse_id", "unit_id", "lot_id") WHERE (lot_id IS NOT NULL);
-- Drop index "inventorytxn_subject_type_subject_id_warehouse_id_occurred_at" from table: "inventory_txns"
DROP INDEX "inventorytxn_subject_type_subject_id_warehouse_id_occurred_at";
-- Modify "inventory_txns" table
ALTER TABLE "inventory_txns" ADD COLUMN "lot_id" bigint NULL, ADD CONSTRAINT "inventory_txns_inventory_lots_inventory_txns" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
-- Create index "inventorytxn_subject_type_subject_id_warehouse_id_lot_id_occurr" to table: "inventory_txns"
CREATE INDEX "inventorytxn_subject_type_subject_id_warehouse_id_lot_id_occurr" ON "inventory_txns" ("subject_type", "subject_id", "warehouse_id", "lot_id", "occurred_at");
